import socket
import json
from threading import Thread
from datetime import datetime

class GameServer:
    def __init__(self):
        self.server_socket = None
        self.player_list = []
        self.game_state = {}
        self.status_queries = 0

    def start_server(self, host='0.0.0.0', port=12345):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.server_socket.bind((host, port))
        print(f"Server started on {host}:{port}")

        thread = Thread(target=self.listen_for_queries)
        thread.daemon = True
        thread.start()

    def listen_for_queries(self):
        while True:
            data, address = self.server_socket.recvfrom(1024)
            if data.decode() == "status":
                self.handle_status_query(address)

    def handle_status_query(self, address):
        self.status_queries += 1
        player_list_json = json.dumps({"players": self.player_list, "game_state": self.game_state})
        self.server_socket.sendto(player_list_json.encode(), address)
        print(f"Sent status response to {address[0]}:{address[1]}")

    def add_player(self, name):
        self.player_list.append(name)

    def update_game_state(self, state):
        self.game_state = state

if __name__ == "__main__":
    game_server = GameServer()
    game_server.start_server()

    # Example usage:
